1	const PROCESSING_FEE = 5;
2	
3	const BASE_PREMIUMS: Record<string, number> = {
4	  sword: 100,
5	  amulet: 60,
6	  staff: 80,
7	  potion: 40,
8	  rune: 25,
9	  moonstone: 25,
10	};
11	
12	const basePremiumForType = (type: string): number => BASE_PREMIUMS[type] ?? 0;
13	
14	const COMPONENT_TYPES = ["rune", "moonstone"];
15	const BLOCK_SIZE = 3;
16	const BLOCK_PREMIUM = 60;
17	
18	const componentPremium = (type: string, count: number): number =>
19	  count === BLOCK_SIZE ? BLOCK_PREMIUM : count * basePremiumForType(type);
20	
21	const calculateQuotePremium = (items: any[]): number => {
22	  const componentCounts: Record<string, number> = {};
23	  let premium = 0;
24	  for (const item of items) {
25	    if (COMPONENT_TYPES.includes(item.type)) {
26	      componentCounts[item.type] = (componentCounts[item.type] ?? 0) + 1;
27	    } else {
28	      const base = basePremiumForType(item.type);
29	      premium += base;
30	      if (item.cursed) premium += base * 0.5;
31	    }
32	  }
33	  for (const [type, count] of Object.entries(componentCounts)) {
34	    premium += componentPremium(type, count);
35	  }
36	  return premium + PROCESSING_FEE;
37	};
38	
39	export const processScenario = (scenario: any): any => ({
40	  results: scenario.steps.map((step: any) => ({
41	    premium: calculateQuotePremium(step.items),
42	  })),
43	});
